import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom'; // Import Routes and Navigate

//import the css and js
import '../../assests/admin/admin/css/styles.css';
import '../../assests/admin/admin/js/scripts.js';

//parts of the layout
import Navbar from './Navbar';
import Sidebar from './Sidebar';
import Footer from "./Footer";

//other imports
import routes from '../../routes/routes.js';

const MasterLayout = () =>
{
    return (
        <div className="sb-nav-fixed">
            <Navbar />
            <div id="layoutSidenav">

                <div id="layoutSidenav_nav">
                    <Sidebar />
                </div>

                <div id="layoutSidenav_content">
                    <main>
                        {/* Use Routes instead of Switch */}
                        <Routes>
                            {
                                routes.map((route, idx) =>
                                {
                                    return (
                                        route.component &&
                                        (
                                            // Use element prop in v6, key is good practice
                                            <Route
                                                key={idx}
                                                path={route.path}
                                                element={<route.component />}
                                            />
                                        )
                                    )
                                })
                            }
                            {/* Use Navigate for redirects in v6. Define a route for the base path. */}
                            <Route path="/admin" element={<Navigate replace to="dashboard" />} />
                        </Routes>

                    </main>
                    <Footer />
                </div>

            </div>
        </div>
    );
}

export default MasterLayout;
